A utility module that converts positive integers to Roman numeral strings.` )};

const _toRoman = function toRoman(){return(
  function toRoman(n) {
    if (n <= 0 || n > 3999 || !Number.isInteger(n)) throw new Error("Expected an integer between 1 and 3999");
    const table = [
      [1000, "M"], [900, "CM"], [500, "D"], [400, "CD"],
      [100, "C"],  [90, "XC"],  [50, "L"],  [40, "XL"],
      [10, "X"],   [9, "IX"],   [5, "V"],   [4, "IV"],
      [1, "I"]
    ];
    let result = "";
    for (const [value, numeral] of table) {
      while (n >= value) { result += numeral; n -= value; }
    }
    return result;
  }
)};

